queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTechniques ?child ; p:hasMakeup_Artists ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Makeup_Artists } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTechniques ?child ; p:hasMakeup_Artists ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Makeup_Artists } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?full_name ?name WHERE {
  ?artist_techniques a :Artist_Techniques .
  ?techniques a :Techniques .
  ?artist_techniques p:hasTechniques ?techniques .
  ?makeup_artists a :Makeup_Artists .
  ?artist_techniques p:hasMakeup_Artists ?makeup_artists .
  ?makeup_artists p:name ?full_name .
  ?techniques p:name ?name .
} }
}
